// Code Node: Calculate email fetch time range based on user's timezone
const userData = $json;
let userTz = userData.timezone || "UTC";

const windowsToIana = {
  "UTC": "UTC",
  "Pacific Standard Time": "America/Los_Angeles",
  "Mountain Standard Time": "America/Denver",
  "Central Standard Time": "America/Chicago",
  "Eastern Standard Time": "America/New_York",
  "India Standard Time": "Asia/Kolkata",
  "China Standard Time": "Asia/Shanghai",
  "Tokyo Standard Time": "Asia/Tokyo",
  "AUS Eastern Standard Time": "Australia/Sydney"
};

function looksLikeIana(tz) {
  return typeof tz === "string" && tz.includes("/") && !tz.includes("Standard Time");
}

if (!looksLikeIana(userTz) && windowsToIana[userTz]) {
  userTz = windowsToIana[userTz];
}

const startUtcISO = $now.setZone(userTz).minus({ hours: 24 }).toUTC().toISO();
const endUtcISO = $now.toUTC().toISO();

console.log(`Timezone: ${userTz}`);
console.log(`Fetching emails from ${startUtcISO} to ${endUtcISO}`);

return [{ json: { ...userData, userTz, startUtcISO, endUtcISO } }];

const allUsers = $input.all();
const activeUsers = allUsers.filter(user => user.json.is_active === true);
console.log(`✓ Found ${activeUsers.length} active users out of ${allUsers.length} total users`);
if (activeUsers.length === 0) throw new Error('No active users found');
return activeUsers;

// Get user info from Merge_Email_Response_With_UserData
const currentUser = $json;
console.log(`\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━`);
console.log(`📧 Processing: ${currentUser.user_name} (${currentUser.user_email})`);
console.log(`━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`);

return [{
  json: {
    userId: currentUser.user_id,
    user_email: currentUser.user_email,
    userName: currentUser.user_name,
    timezone: currentUser.timezone || 'America/New_York',
    access_token: currentUser.access_token,
    refreshToken: currentUser.refresh_token,
    tokenExpiresAt: currentUser.token_expires_at,
    tokenExpiresAtUnix: currentUser.token_expires_at_unix,
    subscriptionId: currentUser.subscription_id,
    subscriptionExpiresAt: currentUser.subscription_expires_at,
    summaryPreference: currentUser.summary_preference,
    processingStartTime: Date.now()
  }
}];

// FORMAT FOR AI - EMAIL SUMMARIZATION WITH ACTION ITEMS
const guardrailsItems = $input.all();

// Get emailIds from Prepare_Email_Data node (before Guardrails)
let emailIdsFromPrepare = [];
try {
  const prepareNode = $('Prepare_Email_Data');
  if (prepareNode && prepareNode.all().length > 0) {
    emailIdsFromPrepare = prepareNode.all().map(item => item.json.emailId);
    console.log(`✓ Retrieved ${emailIdsFromPrepare.length} emailIds from Prepare_Email_Data`);
  }
} catch (e) {
  console.error('Failed to get emailIds from Prepare_Email_Data:', e.message);
}

// If Prepare_Email_Data doesn't have emailIds, try HTTP Request (raw data)
if (emailIdsFromPrepare.length === 0) {
  try {
    const httpNode = $('HTTP Request');
    if (httpNode && httpNode.first().json.value) {
      emailIdsFromPrepare = httpNode.first().json.value.map(email => email.id);
      console.log(`✓ Retrieved ${emailIdsFromPrepare.length} emailIds from HTTP Request`);
    }
  } catch (e) {
    console.error('Failed to get emailIds from HTTP Request:', e.message);
  }
}

return guardrailsItems.map((item, index) => {
  // Get the masked content from Guardrails
  const maskedContent = item.json.guardrailsInput;

  if (!maskedContent) {
    throw new Error(`No guardrailsInput found for item ${index}. Check Guardrails node.`);
  }

  // Parse the masked content
  const lines = maskedContent.split('\n');
  let subject = '';
  let from = '';
  let domain = '';
  let body = '';

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    if (line.startsWith('Subject: ')) {
      subject = line.replace('Subject: ', '').trim();
    } else if (line.startsWith('From: ')) {
      from = line.replace('From: ', '').trim();
    } else if (line.startsWith('Domain: ')) {
      domain = line.replace('Domain: ', '').trim();
    } else if (line.startsWith('Body: ')) {
      body = lines.slice(i).join('\n').replace('Body: ', '').trim();
      break;
    }
  }

  // Create AI summarization prompt
  const aiPrompt = `Act as my executive assistant and analyze this email.

**Email Details:**
Subject: ${subject}
From: ${from}
Domain: ${domain}

**Email Body:**
${body}

**Privacy Notice:**
Some content is masked for security:
- <EMAIL_ADDRESS> = email address (redacted)
- <URL> = web address (redacted)
- <SECRET> = sensitive information (redacted)
- <MEETING_ID> = meeting ID (redacted)
- <PASSCODE> = passcode (redacted)

Focus on the unmasked context, keywords, and patterns to understand intent.

**Your Task:**
1. Summarize this email in 2-3 concise bullet points
2. Extract ALL action items with deadlines (if mentioned)
3. Identify the urgency level (URGENT, HIGH, MEDIUM, LOW)
4. Note the email type (Meeting, Request, FYI, Promotional, etc.)

**Response Format (JSON only):**
{
  "summary": [
    "Key point 1",
    "Key point 2",
    "Key point 3"
  ],
  "actionItems": [
    {
      "action": "What needs to be done",
      "deadline": "Date/time or 'Not specified'",
      "priority": "HIGH/MEDIUM/LOW"
    }
  ],
  "urgency": "URGENT|HIGH|MEDIUM|LOW",
  "emailType": "Meeting|Request|FYI|Promotional|OOO|System",
  "requiresResponse": true|false,
  "estimatedReadTime": "30 seconds",
  "keyInsight": "Most important takeaway in one sentence"
}

**Guidelines:**
- Keep summary bullets under 20 words each
- If no action items, return empty array []
- If no deadline mentioned, use "Not specified"
- Be concise but don't miss critical information
- Focus on what I need to know and do`;

  // ============= CRITICAL: Get real emailId from Prepare_Email_Data =============
  const emailId = emailIdsFromPrepare[index];

  if (!emailId) {
    throw new Error(
      `No emailId found at index ${index}.\n` +
      `Retrieved ${emailIdsFromPrepare.length} emailIds total.\n` +
      `This usually means Prepare_Email_Data or HTTP Request didn't execute properly.`
    );
  }

  // Validate emailId (Microsoft Graph IDs are long)
  if (emailId.startsWith('item-') || emailId.length < 50) {
    throw new Error(
      `Invalid emailId at index ${index}: "${emailId}"\n` +
      `EmailId is too short or has wrong format.\n` +
      `Check Prepare_Email_Data output to ensure email.id is being captured.`
    );
  }

  console.log(`Item ${index}: emailId=${emailId.substring(0, 30)}..., subject=${subject}`);

  return {
    json: {
      itemIndex: index,
      subject: subject,
      from: from,
      domain: domain,

      // AI Prompt for summarization
      aiPrompt: aiPrompt,

      // CRITICAL: Include the real emailId here
      emailId: emailId,

      // Original content
      maskedContent: maskedContent,

      // Metadata
      guardrailsApplied: true,
      processedAt: new Date().toISOString(),
      checks: item.json.checks || null
    }
  };
});

// PARSE AI SUMMARIZATION OUTPUT
const aiOutputItems = $input.all();

// Get original email data from Format_for_AI node
let originalEmailData = [];
try {
  const formatNode = $('Format_for_AI1');
  if (formatNode && formatNode.all().length > 0) {
    originalEmailData = formatNode.all().map(item => item.json);
    console.log(`✓ Retrieved ${originalEmailData.length} emails from Format_for_AI`);
  }
} catch (e) {
  console.error('Failed to get data from Format_for_AI:', e.message);
}

// Get userData (accessToken, userEmail, userId) from Intelligent_Filtering1
let userData = {};
try {
  const mergeNode = $('Merge_Email_Response_With_UserData');
  if (mergeNode && mergeNode.first()) {
    userData = mergeNode.first().json.userData || {};
    console.log(`✓ Retrieved userData for ${userData.user_email}`);
  }
} catch (e) {
  console.error('Failed to get userData from Merge_Email_Response_With_UserData:', e.message);
}

// Extract the data array from the first item
const dataArray = aiOutputItems[0]?.json?.data || [];

if (dataArray.length === 0) {
  throw new Error('No AI output data found in input');
}

console.log(`Processing ${dataArray.length} AI outputs`);

// ✅ NEW: Process all emails into an array
const processedEmails = dataArray.map((item, index) => {
  const rawOutput = item.output;

  if (!rawOutput) {
    console.error(`No output found at index ${index}`);
    return {
      error: true,
      errorMessage: 'No output found',
      index: index
    };
  }

  let aiData;
  try {
    aiData = JSON.parse(rawOutput);
  } catch (parseError) {
    console.error(`Failed to parse AI output at index ${index}:`, parseError.message);
    return {
      error: true,
      errorMessage: `Failed to parse AI response`,
      index: index,
      rawOutput: rawOutput
    };
  }

  const originalEmail = originalEmailData[index] || {};
  const summary = aiData.summary || [];
  const actionItems = aiData.actionItems || [];
  const urgency = aiData.urgency || 'MEDIUM';
  const emailType = aiData.emailType || 'Unknown';
  const requiresResponse = aiData.requiresResponse !== undefined ? aiData.requiresResponse : false;
  const estimatedReadTime = aiData.estimatedReadTime || 'Unknown';
  const keyInsight = aiData.keyInsight || '';

  const actionItemsCount = actionItems.length;
  const highPriorityActions = actionItems.filter(a => a.priority === 'HIGH').length;
  const hasDeadlines = actionItems.some(a => a.deadline !== 'Not specified');

  const urgencyIndicator = {
    'URGENT': '🔴',
    'HIGH': '🟠',
    'MEDIUM': '🟡',
    'LOW': '🟢'
  }[urgency] || '⚪';

  console.log(`✓ Processed email ${index + 1}: ${originalEmail.subject || 'No subject'}`);

  // ✅ Return email data WITHOUT user credentials
  return {
    emailId: originalEmail.emailId,
    subject: originalEmail.subject,
    from: originalEmail.from,
    domain: originalEmail.domain,
    summary: summary,
    actionItems: actionItems,
    actionItemsCount: actionItemsCount,
    urgency: urgency,
    urgencyIndicator: urgencyIndicator,
    emailType: emailType,
    requiresResponse: requiresResponse,
    estimatedReadTime: estimatedReadTime,
    keyInsight: keyInsight,
    metrics: {
      totalActions: actionItemsCount,
      highPriorityActions: highPriorityActions,
      hasDeadlines: hasDeadlines,
      needsReply: requiresResponse,
      isUrgent: urgency === 'URGENT' || urgency === 'HIGH'
    },
    processedAt: new Date().toISOString()
  };
});

// ✅ NEW: Return a SINGLE item with emails array + user credentials
// At the end of Parse AI Output1, update the return statement:

return [{
  json: {
    emails: processedEmails,

    // User credentials at the top level (shared by all emails)
    accessToken: userData.access_token,
    userEmail: userData.user_email,
    userId: userData.userId,
    summaryPreference: userData.summaryPreference, 

    // Metadata
    totalEmails: processedEmails.length,
    processedAt: new Date().toISOString()
  }
}];

// ============= UNIVERSAL PII MASKING FUNCTION =============
function maskAllPII(text) {
  if (!text) return text;

  let masked = text;

  // Define masking patterns in order of specificity (most specific first)
  const patterns = [
    // ===== SECTION 1: GOVERNMENT IDs (MOST SPECIFIC) =====
    {
      regex: /\b(Passport|Passport\s*Number|Passport\s*#|Travel\s*Document)[\s:]+([A-Z]?\d{6,9})\b/gi,
      replacement: (match, label) => `${label}: <PASSPORT>`
    },
    {
      regex: /\b(Aadhaar|Aadhar)[\s:]+(\d{4}\s+\d{4}\s+\d{4})\b/gi,
      replacement: (match, label) => `${label}: <AADHAAR>`
    },
    {
      regex: /\b(PAN|PAN\s*Number)[\s:]+([A-Z]{5}\d{4}[A-Z])\b/gi,
      replacement: (match, label) => `${label}: <PAN>`
    },
    {
      regex: /\b(National\s*Insurance|NI\s*Number)[\s:]+([A-Z]{2}\s*\d{2}\s*\d{2}\s*\d{2}\s*[A-Z])\b/gi,
      replacement: (match, label) => `${label}: <NI_NUMBER>`
    },
    {
      regex: /\b(SSN|Social\s*Security\s*Number|Social\s*Security)[\s:]+(\d{3}[-\s]\d{2}[-\s]\d{4})\b/gi,
      replacement: (match, label) => `${label}: <SSN>`
    },
    {
      regex: /\b(EIN|Tax\s*ID|Employer\s*ID)[\s:]+(\d{2}[-\s]\d{7})\b/gi,
      replacement: (match, label) => `${label}: <EIN>`
    },
    {
      regex: /\b(Driver'?s?\s*License|DL|License\s*Number|Driving\s*License|Licence)[\s:]+([A-Z]{2}\s*[A-Z0-9\s-]{5,15})\b/gi,
      replacement: (match, label) => `${label}: <LICENSE>`
    },
    {
      regex: /\b(National\s*ID|ID\s*Number|Citizen\s*ID|Tax\s*ID|Taxpayer\s*ID|TIN|Registration\s*Number)[\s:]+([A-Z0-9\s-]{6,20})\b/gi,
      replacement: (match, label) => `${label}: <GOV_ID>`
    },

    // ===== SECTION 2: DATES (BEFORE OTHER PATTERNS) =====
    {
      regex: /\b(DOB|Date\s*of\s*Birth|Birth\s*Date|Born|Birthday)[\s:]+([A-Za-z]+\s+\d{1,2},?\s+\d{4})\b/gi,
      replacement: (match, label) => `${label}: <DOB>`
    },
    {
      regex: /\b(DOB|Date\s*of\s*Birth|Birth\s*Date|Birthday)[\s:]+(\d{1,2}[-/]\d{1,2}[-/]\d{2,4})\b/gi,
      replacement: (match, label) => `${label}: <DOB>`
    },
    {
      regex: /\b(Expires|Expiration|Exp\s*Date|Valid\s*Until|Exp)[\s:]+(\d{2}\/\d{2,4}|\d{2}[-]\d{2,4})\b/gi,
      replacement: (match, label) => `${label}: <EXPIRY_DATE>`
    },
    {
      regex: /\b(Contract\s*Renewal|Renewal\s*Date|Contract\s*Date|Expiry)[\s:]+(\d{1,2}\/\d{1,2}\/\d{2,4})\b/gi,
      replacement: (match, label) => `${label}: <CONTRACT_DATE>`
    },
    {
      regex: /\b(Customer\s*Since|Member\s*Since|Client\s*Since|Joined|Registered)[\s:]+(\d{1,2}\/\d{1,2}\/\d{2,4})\b/gi,
      replacement: (match, label) => `${label}: <MEMBER_DATE>`
    },
    {
      regex: /\b(Last\s*Purchase|Purchase\s*Date|Order\s*Date)[\s:]+(\d{1,2}\/\d{1,2}\/\d{4})\b/gi,
      replacement: (match, label) => `${label}: <PURCHASE_DATE>`
    },

    // ===== SECTION 3: CONTACT INFORMATION =====
    {
      regex: /\+\d{1,4}[\s\-]?\d{2,4}[\s\-]?\d{3,4}[\s\-]?\d{3,5}/g,
      replacement: '<PHONE>'
    },
    {
      regex: /\b\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}\b/g,
      replacement: '<PHONE>'
    },
    {
      regex: /\b(Phone|Telephone|Tel|Mobile|Cell|Contact|Emergency|Fax|Direct|Office|Home|Work)[\s:]+([+\d\s\-().]{8,20})\b/gi,
      replacement: (match, label) => `${label}: <PHONE>`
    },
    {
      regex: /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g,
      replacement: '<EMAIL>'
    },

    // ===== SECTION 4: FINANCIAL - CREDIT CARDS =====
    {
      regex: /\b(?:\d{4}[-\s]?){3}\d{4}\b/g,
      replacement: '<CARD>'
    },
    {
      regex: /\b(?:\*{4}|X{4}|xxxx)[\s\-]?(?:\*{4}|X{4}|xxxx)[\s\-]?(?:\*{4}|X{4}|xxxx)[\s\-]?\d{4}\b/gi,
      replacement: '<CARD>'
    },
    {
      regex: /\b(Credit\s*Card|Card|Amex|Visa|Mastercard|Corporate\s*Amex)[\s:]*\([^)]*last\s*4[\s:]*(\d{4})\)/gi,
      replacement: (match, label) => `${label.trim()} (last 4: <CARD_LAST4>)`
    },
    {
      regex: /\b(Credit\s*Card|Card)[\s:]*(?:ending\s*in|last\s*4)[\s:]*(\d{4})\b/gi,
      replacement: (match, label) => `${label}: <CARD_LAST4>`
    },
    {
      regex: /\b(Card\s*Type|Type)[\s:]+\b(Visa|Mastercard|Master\s*Card|American\s*Express|Amex|Discover|Diners|JCB|UnionPay)\b/gi,
      replacement: (match, label) => `${label}: <CARD_TYPE>`
    },
    {
      regex: /\b(CVV|Security\s*Code|CVC)[\s:]+(\d{3,4})\b/gi,
      replacement: (match, label) => `${label}: <CVV>`
    },

    // ===== SECTION 5: FINANCIAL - BANK ACCOUNTS =====
    {
      regex: /\b[A-Z]{2}\d{2}\s*[A-Z0-9]{4}\s*\d{4}\s*\d{4}\s*\d{4}\s*\d{2,4}\b/g,
      replacement: '<IBAN>'
    },
    {
      regex: /\b(Sort\s*Code)[\s:]+(\d{2}[-\s]\d{2}[-\s]\d{2})\b/gi,
      replacement: (match, label) => `${label}: <SORT_CODE>`
    },
    {
      regex: /\b(IFSC\s*Code|IFSC)[\s:]+([A-Z]{4}0[A-Z0-9]{6})\b/gi,
      replacement: (match, label) => `${label}: <IFSC>`
    },
    {
      regex: /\b(SWIFT|SWIFT\s*Code|BIC)[\s:]+([A-Z]{4}[A-Z]{2}[A-Z0-9]{2}(?:[A-Z0-9]{3})?)\b/gi,
      replacement: (match, label) => `${label}: <SWIFT>`
    },
    {
      regex: /\b(Routing|Routing\s*Number|ABA)[\s:]+(\d{9})\b/gi,
      replacement: (match, label) => `${label}: <ROUTING>`
    },
    {
      regex: /\b(Bank\s*Account|Account\s*Number|Account|Savings\s*Account|Checking\s*Account)[\s:]+(?:\*{4}|X{4}|xxxx)\d{4,6}\b/gi,
      replacement: (match, label) => `${label}: <ACCOUNT>`
    },
    {
      regex: /\b(Account\s*Number|Account|Bank\s*Account|Savings\s*Account|Checking\s*Account)[\s:]+([A-Z0-9\s-]{8,20})\b/gi,
      replacement: (match, label) => `${label}: <ACCOUNT>`
    },

    // ===== SECTION 6: CURRENCY & AMOUNTS =====
    // Specific labeled amounts first
    {
      regex: /\b(Account\s*Value|Annual\s*Value|Contract\s*Value|Total|Amount|Balance|Revenue|Payment|Price|Cost|Fee|Charge|Salary|Wage|Income|Profit|Loss|Budget|Spend|Invoice|Bill|Rate|Premium|Tax|VAT|GST|Sales\s*Tax|Discount|Rebate|Refund|Penalty|Fine|Surcharge|Debit|Credit|Withdrawal|Deposit|Transfer)[\s:]+\$?[\d,]+\.?\d{0,2}(?:\/year|\/month|\/quarter|\/day|\/hour|per\s+year|per\s+month|annually|monthly)?%?\b/gi,
      replacement: (match, label) => `${label}: <AMOUNT>`
    },
    // Currency symbols
    {
      regex: /[$€£¥₹₽₩₪₦₱₡₴₵₸₺¤][\d,]+\.?\d{0,2}\b/g,
      replacement: '<AMOUNT>'
    },
    // Currency codes before amount
    {
      regex: /\b(USD|EUR|GBP|JPY|CNY|INR|CAD|AUD|CHF|SEK|NZD|SGD|HKD|KRW|MXN|BRL|ZAR|RUB|AED|SAR)\s+[\d,]+\.?\d{0,2}\b/gi,
      replacement: '<AMOUNT>'
    },
    // Currency codes after amount
    {
      regex: /\b[\d,]+\.?\d{0,2}\s+(USD|EUR|GBP|JPY|CNY|INR|CAD|AUD|CHF|SEK|NZD|SGD|HKD|KRW|MXN|BRL|ZAR|RUB|AED|SAR)\b/gi,
      replacement: '<AMOUNT>'
    },
    // Abbreviated amounts
    {
      regex: /\$[\d,]+\.?\d{0,2}\s*([KMBT]|million|billion|trillion|thousand)\b/gi,
      replacement: '<AMOUNT>'
    },
    {
      regex: /\b[\d,]+\.?\d{0,2}\s*([KMBT]|million|billion|trillion|thousand)\s+(USD|EUR|GBP|dollars|euros|pounds)\b/gi,
      replacement: '<AMOUNT>'
    },
    // Negative amounts
    {
      regex: /-\$[\d,]+\.?\d{0,2}\b/g,
      replacement: '<AMOUNT>'
    },
    {
      regex: /\(\$?[\d,]+\.?\d{0,2}\)/g,
      replacement: '<AMOUNT>'
    },
    // Amount ranges
    {
      regex: /\$[\d,]+\.?\d{0,2}\s*[-–—]\s*\$?[\d,]+\.?\d{0,2}\b/g,
      replacement: '<AMOUNT_RANGE>'
    },
    {
      regex: /\$[\d,]+\.?\d{0,2}\s+to\s+\$?[\d,]+\.?\d{0,2}\b/gi,
      replacement: '<AMOUNT_RANGE>'
    },
    // European format
    {
      regex: /\b\d{1,3}(?:\.\d{3})+,\d{2}\b/g,
      replacement: '<AMOUNT>'
    },
    // Amounts in sentences
    {
      regex: /\b(paid|worth|costs?|valued|priced|charged|invoiced|billed)\s+\$?[\d,]+\.?\d{0,2}\b/gi,
      replacement: (match, verb) => `${verb} <AMOUNT>`
    },

    // ===== SECTION 7: PERCENTAGES & METRICS =====
    {
      regex: /\b\d+\.?\d{0,4}%\b/g,
      replacement: '<PERCENTAGE>'
    },
    {
      regex: /\b(P\/E\s*Ratio|ROI|APR|APY|Interest\s*Rate|Rate|Ratio|Multiple|Margin)[\s:]+\d+\.?\d{0,4}%?\b/gi,
      replacement: (match, label) => `${label}: <METRIC>`
    },

    // ===== SECTION 8: ADDRESSES (AFTER DATES TO AVOID CONFLICTS) =====
    {
      regex: /\b(Address|Home\s*Address|Business\s*Address|UK\s*Address|India\s*Address|Mailing\s*Address|Billing\s*Address|Shipping\s*Address)[\s:]+([^\n]{15,150}(?:Street|St|Avenue|Ave|Road|Rd|Boulevard|Blvd|Lane|Ln|Drive|Dr|Court|Ct|Flat|Suite|Apartment|Building|Sector|District|Kingdom|India|USA|UK)[^\n]{0,50})/gi,
      replacement: (match, label) => `${label}: <ADDRESS>`
    },
    {
      regex: /\b(Flat|Apartment|Apt|Unit|Suite|Building)\s+[A-Za-z0-9-]+[,\s]*[^\n]{0,100}/gi,
      replacement: '<ADDRESS>'
    },
    {
      regex: /\b\d{1,6}\s+[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,4}\s*(?:Street|St|Avenue|Ave|Road|Rd|Boulevard|Blvd|Lane|Ln|Drive|Dr|Court|Ct)[^\n,]{0,50}/gi,
      replacement: '<ADDRESS>'
    },
