function processEmails() {
  const items = $input.all();

  if (!items || items.length === 0) {
    console.log('No emails to process');
    return [];
  }

  console.log(`\n=== Processing ${items.length} emails ===\n`);

  const results = items.map((item, index) => {
    const email = item.json;

    // Validate email object
    if (!email?.id || !email?.subject) {
      console.log(`⚠️  Email ${index + 1}: Invalid email object, skipping`);
      return null;
    }

    // Extract sender information
    const senderInfo = extractSenderInfo(email.from);

    // Get and mask email content
    const bodyContent = email.data || email.bodyPreview || email.body?.content || '';
    const maskedBody = maskAllPII(bodyContent);
    const maskedSubject = maskAllPII(email.subject || '');

    // Create content for AI
    const contentForAI = `Subject: ${maskedSubject}
From: ${senderInfo.email}
Domain: ${senderInfo.domain}
Body: ${maskedBody}`;

    // Analyze PII
    const piiAnalysis = analyzePII(maskedBody);

    console.log(`✅ Email ${index + 1}/${items.length}: "${email.subject}" - Found ${piiAnalysis.totalPII} PII items`);

    return {
      json: {
        emailId: email.id,
        maskedSubject,
        contentForAI,
        senderDomain: senderInfo.domain,
        hasAttachments: email.hasAttachments || false,
        importance: email.importance || 'normal',
        receivedDateTime: email.receivedDateTime,

        // PII Risk Assessment
        piiDetected: piiAnalysis.totalPII > 0,
        piiCount: piiAnalysis.totalPII,
        piiTypes: piiAnalysis.types,
        piiRiskLevel: calculateRiskLevel(piiAnalysis.totalPII),

      }
    };
  }).filter(item => item !== null);

  console.log(`\n=== Processed ${results.length} emails successfully ===\n`);
  return results;
}

// ============= HELPER FUNCTIONS =============
function extractSenderInfo(from) {
  let email = '';
  let domain = '';

  if (from) {
    if (typeof from === 'string') {
      email = from;
      domain = from.split('@')[1] || '';
    } else if (from.emailAddress) {
      email = from.emailAddress.address || '';
      domain = email.split('@')[1] || '';
    }
  }

  return { email, domain };
}

function analyzePII(maskedText) {
  const piiPatterns = {
    ssn: /<SSN>/g,
    ein: /<EIN>/g,
    aadhaar: /<AADHAAR>/g,
    pan: /<PAN>/g,
    niNumber: /<NI_NUMBER>/g,
    govId: /<GOV_ID>/g,
    passport: /<PASSPORT>/g,
    license: /<LICENSE>/g,
    dob: /<DOB>/g,
    phone: /<PHONE>/g,
    email: /<EMAIL>/g,
    address: /<ADDRESS>/g,
    name: /<NAME>/g,
    account: /<ACCOUNT>/g,
    iban: /<IBAN>/g,
    sortCode: /<SORT_CODE>/g,
    ifsc: /<IFSC>/g,
    swift: /<SWIFT>/g,
    routing: /<ROUTING>/g,
    card: /<CARD>/g,
    password: /<PASSWORD>/g,
    username: /<USERNAME>/g,
    apiKey: /<API_KEY>/g,
    ip: /<IP>/g,
    securityQuestion: /<SECURITY_QUESTION>/g,
    securityAnswer: /<SECURITY_ANSWER>/g
  };

  const types = {};
  let totalPII = 0;

  Object.entries(piiPatterns).forEach(([key, pattern]) => {
    const count = (maskedText.match(pattern) || []).length;
    types[key] = count;
    totalPII += count;
  });

  return { types, totalPII };
}

function calculateRiskLevel(piiCount) {
  if (piiCount === 0) return 'none';
  if (piiCount <= 3) return 'low';
  if (piiCount <= 7) return 'medium';
  return 'high';
}

